const now = new Date();
const start = new Date(now.getFullYear(), now.getMonth(), 1);
const end = new Date(now.getFullYear(), now.getMonth() + 1, 1);

const rows = items.map(i => i.json);

// adjust these keys to your sheet column names
// Date, Type, Category, Description, Amount, Source
const filtered = rows.filter(r => {
  const d = new Date(r.Date);
  return d >= start && d < end;
});

return filtered.map(r => ({ json: r }));

const rows = items.map(i => i.json);

const wantCategories = new Set(["miscellaneous", "self-care"]); // adjust if you want
const expenseTotals = {};
const incomeTotals = {};

let totalExpense = 0;
let totalIncome = 0;
let needs = 0;
let wants = 0;

for (const r of rows) {
  const type = (r.Type || "").toLowerCase();
  const cat = (r.Category || "").toLowerCase();
  const amt = Number(r.Amount || 0);

  if (type === "income") {
    incomeTotals[cat] = (incomeTotals[cat] || 0) + amt;
    totalIncome += amt;
  } else {
    expenseTotals[cat] = (expenseTotals[cat] || 0) + amt;
    totalExpense += amt;

    if (wantCategories.has(cat)) wants += amt;
    else needs += amt;
  }
}

const needsPct = totalExpense ? (needs / totalExpense) * 100 : 0;
const wantsPct = totalExpense ? (wants / totalExpense) * 100 : 0;

return [{
  json: {
    totalExpense,
    totalIncome,
    expenseTotals,
    incomeTotals,
    needs,
    wants,
    needsPct,
    wantsPct,
  }
}];

const text = ($json.text || "").trim().toLowerCase();

// Supports:
// "current" -> today
// "current 2026-02-28" -> that date (YYYY-MM-DD)
let target = null;

const m = text.match(/^current\s+(\d{4}-\d{2}-\d{2})$/);
if (m) {
  target = m[1];
} else {
  // today (local runtime time)
  const now = new Date();
  const yyyy = now.getFullYear();
  const mm = String(now.getMonth() + 1).padStart(2, "0");
  const dd = String(now.getDate()).padStart(2, "0");
  target = `${yyyy}-${mm}-${dd}`;
}

return [{ json: { ...$json, target_date: target } }];

const target = $('Parse current date').first().json.target_date; // YYYY-MM-DD

const filtered = items.filter(i => {
  const raw = i.json.Date || "";
  const d = String(raw).slice(0, 10);
  return d === target;
});

// If none matched, return ONE placeholder item so workflow continues
if (filtered.length === 0) {
  return [{
    json: {
      _no_rows: true,
      Date: `${target}T00:00:00.000Z`,
      Type: "",
      Category: "",
      Description: "",
      Amount: 0,
      Source: "",
    }
  }];
}

return filtered;

const target = $('Parse current date').first().json.target_date; // YYYY-MM-DD

let totalExpense = 0;
let totalIncome = 0;

const expenseTotals = {};
const incomeTotals = {};

// Ignore placeholder rows
const rows = items.map(i => i.json).filter(r => !r._no_rows);

for (const r of rows) {
  const type = String(r.Type || "").toLowerCase();
  const cat = String(r.Category || "uncategorized").toLowerCase();
  const amt = Number(r.Amount || 0);

  if (type === "income") {
    incomeTotals[cat] = (incomeTotals[cat] || 0) + amt;
    totalIncome += amt;
  } else {
    expenseTotals[cat] = (expenseTotals[cat] || 0) + amt;
    totalExpense += amt;
  }
}

return [{
  json: {
    target_date: target,
    totalExpense,
    totalIncome,
    expenseTotals,
    incomeTotals,
    count: rows.length,
    no_transactions: rows.length === 0,
  }
}];

const rows = items.map(i => i.json);

// Normalize helpers
const normSource = (s) => String(s ?? '').trim() || 'Unknown';
const toNumber = (v) => {
  const n = Number(String(v ?? '').replace(/,/g, '').trim());
  return Number.isFinite(n) ? n : 0;
};

const balances = {};
let total = 0;

for (const r of rows) {
  const source = normSource(r.Source);
  const amt = toNumber(r.Amount);

  balances[source] = (balances[source] || 0) + amt;
  total += amt;
}

// Create a sorted array for output formatting
const breakdown = Object.entries(balances)
  .map(([source, amount]) => ({ source, amount }))
  .sort((a, b) => b.amount - a.amount);

return [{
  json: {
    breakdown,
    total,
    count: rows.length,
    no_rows: rows.length === 0,
  }
}];

