// Server is UTC. +8 = PHT.
const now = new Date(new Date().getTime() + 8 * 60 * 60 * 1000);

function toDateStr(d) {
  const y = d.getUTCFullYear();
  const m = String(d.getUTCMonth() + 1).padStart(2, '0');
  const dd = String(d.getUTCDate()).padStart(2, '0');
  return `${y}-${m}-${dd}`;
}

// Last Sunday → today (this Sunday)
const dow = now.getUTCDay(); // 0 = Sunday in PHT
const lastSunday = new Date(now);
lastSunday.setUTCDate(now.getUTCDate() - dow - 7);

return [{
  json: {
    ...$json,
    report_start: toDateStr(lastSunday),
    report_end:   toDateStr(now),
    reportType:   "weekly",
  }
}];

